/**
 * @summary Ask the assistant a question
 */
export const getAskAssistantUrl = () => {
  return `/api/dashboard/assistant`;
};

export const askAssistant = async (
  assistantQuestion: AssistantQuestion,
  options?: RequestInit,
): Promise<AssistantAnswer> => {
  return customFetch<AssistantAnswer>(getAskAssistantUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(assistantQuestion),
  });
};

export const getAskAssistantMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof askAssistant>>,
    TError,
    { data: BodyType<AssistantQuestion> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof askAssistant>>,
  TError,
  { data: BodyType<AssistantQuestion> },
  TContext
> => {
  const mutationKey = ["askAssistant"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof askAssistant>>,
    { data: BodyType<AssistantQuestion> }
  > = (props) => {
    const { data } = props ?? {};

    return askAssistant(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type AskAssistantMutationResult = NonNullable<
  Awaited<ReturnType<typeof askAssistant>>
>;
export type AskAssistantMutationBody = BodyType<AssistantQuestion>;
export type AskAssistantMutationError = ErrorType<unknown>;

/**
 * @summary Ask the assistant a question
 */
export const useAskAssistant = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof askAssistant>>,
    TError,
    { data: BodyType<AssistantQuestion> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof askAssistant>>,
  TError,
  { data: BodyType<AssistantQuestion> },
  TContext
> => {
  return useMutation(getAskAssistantMutationOptions(options));
};
